sql:
SELECT AVG(julianday(processing_date) - julianday(return_date)) AS average_processing_time
FROM returns_and_refunds
WHERE STRFTIME('%Y', processing_date) = '2022' AND is_processed = 1;

SELECT invoices.invoice_id, customers.customer_name
FROM invoices
INNER JOIN customers ON invoices.customer_id = customers.customer_id;

SELECT customer_name
FROM customers
WHERE customer_id IN (SELECT DISTINCT customer_id FROM invoices);

SELECT description, total_price, warranty_period
FROM invoice_items
WHERE returnable = 1 AND quantity > 0;

SELECT COUNT(item_id) AS total_returned_items
FROM returns_and_refunds
WHERE return_date > '2023-10-01 10:00:00' AND refund_amount > 0;

SELECT country, SUM(monetary_value) AS Total_Sales
FROM invoices
GROUP BY country;

SELECT invoice_id, invoice_number, invoice_date, monetary_value, tax_amount, discount_amount, status
FROM invoices
WHERE customer_id = 100 AND country = 'United States';

SELECT AVG(num_items) AS average_items_per_invoice
FROM (
    SELECT invoice_id, COUNT(*) AS num_items
    FROM invoice_items
    GROUP BY invoice_id
);

SELECT customer_id, payment_method 
FROM invoices 
WHERE monetary_value > 1000;

SELECT * FROM invoices
WHERE salesperson_id = (
    SELECT user_id FROM users WHERE user_name = 'Bob Williams'
)
AND year = 2022;

SELECT COUNT(*) AS total_invoices
FROM invoices
WHERE salesperson_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

external_knowledge:
- "stars" metaphorically refers to customers;
- "showered more than a thousand dollars in revenue" metaphorically refers to customers having a lifetime value greater than 1000;
- "holiday month of December 2022" refers to the date range from December 1st, 2022, to December 30th, 2022;
- "casting their light upon our invoices" metaphorically refers to making purchases or creating invoices.

